        c->reason = REASON_SHORT;
        snprintf(c->msg, sizeof(c->msg), "header short");
        return -3;
    }
    if (hdr.magic != VAULT_MAGIC) {
        fclose(in);
        c->reason = REASON_MAGIC;
        snprintf(c->msg, sizeof(c->msg), "bad magic 0x%x", hdr.magic);
        return -4;
