    int n_cells = 0;
    fread(&n_cells, sizeof(int), 1, in);
    b->grid.n = n_cells;
    fread(b->grid.cells, sizeof(CellView), n_cells, in);
    memset(&b->topo, 0, sizeof(b->topo));
    b->bank.n_pending = 0;
